#[test]
fn dg_basis_matches_derivation_p1() {
    let re = ReferenceElement::new(1);
    assert_eq!(re.n_nodes, 4, "Np for p=1");
    let m_err = max_rel_err(&re.mass, &MASS_P1);
    let dr_err = max_rel_err(&re.diff_r, &DR_P1);
    let ds_err = max_rel_err(&re.diff_s, &DS_P1);
    let dt_err = max_rel_err(&re.diff_t, &DT_P1);
    eprintln!(
        "p=1: max rel err  M {:.2e}  Dr {:.2e}  Ds {:.2e}  Dt {:.2e}",
        m_err, dr_err, ds_err, dt_err
    );
    assert!(m_err < 1e-9, "mass mismatch (p=1): {:.2e}", m_err);
    assert!(dr_err < 1e-9, "diff_r mismatch (p=1): {:.2e}", dr_err);
    assert!(ds_err < 1e-9, "diff_s mismatch (p=1): {:.2e}", ds_err);
    assert!(dt_err < 1e-9, "diff_t mismatch (p=1): {:.2e}", dt_err);
}

