#[test]
fn dg_basis_matches_derivation_p3() {
    let re = ReferenceElement::new(3);
    assert_eq!(re.n_nodes, 20, "Np for p=3");
    let m_err = max_rel_err(&re.mass, &MASS_P3);
    let dr_err = max_rel_err(&re.diff_r, &DR_P3);
    let ds_err = max_rel_err(&re.diff_s, &DS_P3);
    let dt_err = max_rel_err(&re.diff_t, &DT_P3);
    eprintln!(
        "p=3: max rel err  M {:.2e}  Dr {:.2e}  Ds {:.2e}  Dt {:.2e}",
        m_err, dr_err, ds_err, dt_err
    );
    assert!(m_err < 1e-9, "mass mismatch (p=3): {:.2e}", m_err);
    assert!(dr_err < 1e-9, "diff_r mismatch (p=3): {:.2e}", dr_err);
    assert!(ds_err < 1e-9, "diff_s mismatch (p=3): {:.2e}", ds_err);
    assert!(dt_err < 1e-9, "diff_t mismatch (p=3): {:.2e}", dt_err);
}
